ee:message.ee:set-payload:
%dw 2.0
import nutrientMapping 
output application/json
var dbColumns = vars.nutrients splitBy ", "
var apiFields = nutrientMapping::mapToApiFields(dbColumns)
var row = payload[0]
var nutrients = dbColumns map ((col, index) -> {
  (apiFields[index] as String): row[col]
}) reduce ((item, acc = {}) -> acc ++ item)
---
if (row != null)
{
  foodId: row.fdc_id,
  name: row.food_name,
  nutrients: nutrients
}
else null

logger.message:
#[%dw 2.0
output application/json
var logMessage ='Requested food details: '++ (vars.name as String)
var foodname= {
	foodName: vars.name
}
import log
---
log::buildLog("INFO",logMessage,foodname, vars.correlationId , vars.flowName)]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	totalResults: sizeOf(payload),
	foods: payload map (item)->{
		foodId: item.fdc_id,
		name: item.food_name,
		category: item.category,
		servingSizeG: item.serving_size_g
	}
}
